parameters.jsCode:
const jobId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c === 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

const body = $input.first().json.body || {};

const url = body.url;
const brand = body.brand;
const website_url = body.website_url;
const language = body.language || 'Indonesian';
const references = body.references || [];

return [{
  json: {
    jobId,
    url,
    brand,
    website_url,
    language,
    references
  }
}];

const job = $input.first()?.json;

if (!job || !job.job_id) {
  return [{
    json: {
      status: 404,
      body: {
        status: 'NOT_FOUND'
      }
    }
  }];
}

if (job.status !== 'DONE') {
  return [{
    json: {
      status: 200,
      body: {
        jobId: job.job_id,
        status: job.status
      }
    }
  }];
}

return [{
  json: {
    status: 200,
    body: {
      jobId: job.job_id,
      status: 'DONE',
      data: {
        id: job.id,
        jobId: job.job_id,
        brandAnalysisJobId: job.brand_analysis_job_id,

        productUrl: job.product_url,
        productName: job.product_name,
        brandName: job.brand_name,
        productType: job.product_type,
        priceTier: job.price_tier,
        productImage: job.product_image,

        productSummary: job.product_summary,
        uniqueSellingProposition: job.unique_selling_proposition,
        reasonToBelieve: job.reason_to_believe,
        functionalBenefits: job.functional_benefits || [],
        emotionalBenefits: job.emotional_benefits || [],
        targetAudience: job.target_audience,

        websiteUrl: job.website_url,
        language: job.language,
        createdAt: job.created_at,
        updatedAt: job.updated_at
      }
    }
  }
}];

parameters.query:
SELECT * FROM brand_product 
WHERE job_id = '{{ $json.query.jobId }}'
LIMIT 1;

